UPDATE public.products SET short_description = 'Biofloxx é um antibiótico de amplo espectro cujo princípio ativo é o cloridrato de ciprofloxacina. Atua inibindo enzimas essenciais para a replicação do DNA bacteriano, sendo usado principalmente no tratamento de infecções graves do trato urinário, respiratório, ossos e pele. Exige receita médica e deve ser usado com cautela, pois pertence à classe das fluoroquinolonas, que possuem risco aumentado de causar tendinites ou rupturas de tendões.' WHERE slug = 'biofloxx-500';